"""family_fp16_4 — FLOAT16-intermediate rebuilds of memory-dominated incumbents.

For each target task the exact float32 solver (out_p5/onnx/taskNNN.onnx) is
re-emitted as a clean SSA graph whose INTERMEDIATE tensors are float16 (2 bytes)
instead of float32 (4 bytes): the FLOAT input is Cast->float16 once at the top,
every float initializer/Constant is converted to float16, every Cast-to-float is
retargeted to float16, and the graph output is declared float16 (the grader only
thresholds ``output > 0``, so the float width is irrelevant to correctness).
Result: byte-identical rule, half the dominant memory term -> +~0.3..0.7 pts.

Every embedded graph was validated to reproduce its task's train+test+arc-gen
pairs EXACTLY (after the >0 threshold) in float16; models where float16 lost
precision (192, 374, 169, 035) were dropped rather than emitted.

Detection is behavioural + self-contained: each embedded model is run on the
given train+test pairs and proposed only if it reproduces every pair exactly, so
it fires on the intended task (and the grader still gates arc-gen).
"""
from __future__ import annotations

import base64
import gzip

import numpy as np
import onnx

try:
    import onnxruntime as _ort
except Exception:  # pragma: no cover
    _ort = None

# task-number -> gzip+base64 of the float16 ONNX model
_MODELS = {
    22: "",
    24: "",
    25: "",
    32: "",
    42: "",
    74: "",
    84: "",
    113: "",
    154: "",
    163: "",
    175: "",
    187: "",
    231: "",
    239: "",
    245: "",
    288: "",
    293: "",
    295: "",
    297: "",
    302: "",
    370: "",
    378: "",
    388: "",
}

_SESS = {}


def _model(task):
    return onnx.load_model_from_string(gzip.decompress(base64.b64decode(_MODELS[task])))


def _session(task):
    s = _SESS.get(task)
    if s is None:
        s = _ort.InferenceSession(
            gzip.decompress(base64.b64decode(_MODELS[task])),
            providers=["CPUExecutionProvider"],
        )
        _SESS[task] = s
    return s


def _onehot(grid):
    g = np.asarray(grid)
    if g.ndim != 2 or g.size == 0 or max(g.shape) > 30:
        return None
    a = np.zeros((1, 10, 30, 30), dtype=np.float32)
    for r in range(g.shape[0]):
        for c in range(g.shape[1]):
            a[0, int(g[r, c]), r, c] = 1.0
    return a


def _pairs(examples):
    prs = []
    for key in ("train", "test"):
        for e in examples.get(key, []) or []:
            xi = _onehot(e["input"])
            yo = _onehot(e["output"])
            if xi is None or yo is None:
                return None
            prs.append((xi, yo > 0))
    return prs or None


def _exact(task, prs):
    if _ort is None:
        return False
    try:
        sess = _session(task)
    except Exception:
        return False
    for xi, ybool in prs:
        try:
            out = sess.run(None, {"input": xi})[0]
        except Exception:
            return False
        if (out > 0).shape != ybool.shape or not ((out > 0) == ybool).all():
            return False
    return True


def candidates(examples):
    prs = _pairs(examples)
    if not prs:
        return []
    out = []
    for task in _MODELS:
        if _exact(task, prs):
            out.append((f"fp16_{task}", _model(task)))
    return out
